module dma_controller (  
    input clk,  
    input reset,  
    input enable,  
    output reg [2:0] active_channel  
);  

    reg [2:0] inactive_channel;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            inactive_channel <= 3'b000;  
            active_channel <= 3'b000;  
        end else if (enable) begin  
            if (inactive_channel < 3'b111)  
                inactive_channel <= inactive_channel + 1;  
            else  
                inactive_channel <= 3'b000;  
            active_channel <= inactive_channel;  
        end  
    end  
endmodule
